const ITEM_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export const KNOWN_ITEM_TYPES: Set<string> = new Set(Object.keys(ITEM_BASE_PREMIUMS));

export function isKnownItemType(type: string): boolean {
  return KNOWN_ITEM_TYPES.has(type);
}

const scenario: Scenario = JSON.parse(readFileSync(0, "utf-8"));

for (const step of scenario.steps) {
  if (step.op === "quote") {
    for (const item of step.items) {
      if (!isKnownItemType(item.type)) {
        process.stderr.write(`error: unknown item type "${item.type}"\n`);
        process.exit(1);
      }
    }
  }
}

process.stdout.write(JSON.stringify({ results: runScenario(scenario) }));
